static constexpr uint32_t ALIGN = 32;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    // GetInputShape returns const gert::Shape*, which has GetDim() directly.
    const gert::Shape *xShape = context->GetInputShape(0);
    const gert::Shape *wI2hShape = context->GetInputShape(2);
    const gert::Shape *wH2oShape = context->GetInputShape(4);

    uint32_t T = xShape->GetDim(0);
    uint32_t B = xShape->GetDim(1);
    uint32_t I = xShape->GetDim(2);
    uint32_t H = wI2hShape->GetDim(0);
    uint32_t O = wH2oShape->GetDim(0);
    uint32_t K = I + H;

    tiling.set_totalSteps(T);
    tiling.set_batchSize(B);
    tiling.set_hiddenSize(H);
    tiling.set_inputSize(I);
    tiling.set_outputSize(O);
    tiling.set_concatSize(K);

    uint32_t tileK = 512;
    uint32_t tileH = 256;
    uint32_t tileO = 128;
    tileK = (tileK / ALIGN) * ALIGN;
    tileH = (tileH / ALIGN) * ALIGN;
    tileO = (tileO / ALIGN) * ALIGN;

    tiling.set_tileK(tileK);
    tiling.set_tileH(tileH);
    tiling.set_tileO(tileO);

    uint32_t blockDim = T;
    if (blockDim > 24) blockDim = 24;
    context->SetBlockDim(blockDim);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
